mapper.update:
UPDATE TBL_REPLY
   SET CONTENT = #{content},
       UPDATED_AT = SYSDATE
 WHERE REPLY_ID = #{reply_id}
   AND USER_ID = #{user_id}

UPDATE TBL_REPLY
   SET IS_ACTIVE = 'N'
 WHERE REPLY_ID = #{reply_id}
   AND USER_ID = #{user_id}

UPDATE TBL_BOARD
   SET REPLY_CNT = (SELECT COUNT(*) FROM TBL_REPLY WHERE BOARD_ID = #{board_id} AND IS_ACTIVE = 'Y')
 WHERE BOARD_ID = #{board_id}
